const repoRoot = $env.PCP_REPO_ROOT || '/opt/saars.inplast';
const data = $json.data || {};
const headerAuth = (($json.headers || {}).authorization) || (($json.headers || {}).Authorization) || '';
const rawAuthorization = $json.authorization || $json.Authorization || $json.bearer || $json.bearer_token || $json.bearerToken || headerAuth || data.authorization || data.Authorization || data.bearer || data.bearer_token || data.bearerToken || '';
const accessToken = $json.access_token || $json.accessToken || $json.token || data.access_token || data.accessToken || data.token || '';
const authorization = rawAuthorization || (accessToken ? (String(accessToken).startsWith('Bearer ') ? String(accessToken) : `Bearer ${accessToken}`) : ($env.SANKHYA_AUTHORIZATION || ''));
return [{
  json: {
    source_code: 'romaneio_sankhya_webhook',
    script_path: `${repoRoot}/scripts/sankhya_ordens_carga_poll.py`,
    workflow_name: 'PCP | 15 | Sankhya | Ordens de Carga Poll',
    list_url: $env.SANKHYA_ORDENS_CARGA_LIST_URL || 'https://api.sankhya.com.br/v1/logistica/ordens-carga',
    detail_url_template: $env.SANKHYA_ORDENS_CARGA_DETAIL_URL_TEMPLATE || 'https://api.sankhya.com.br/v1/logistica/empresas/{codigoEmpresa}/ordens-carga/{codigoOrdemCarga}',
    pedidos_url_template: $env.SANKHYA_ORDENS_CARGA_PEDIDOS_URL_TEMPLATE || '',
    authorization,
    codigo_empresa: $env.SANKHYA_CODIGO_EMPRESA || '',
    modified_since: $env.SANKHYA_ORDENS_CARGA_MODIFIED_SINCE || '',
    page: Number($env.SANKHYA_ORDENS_CARGA_PAGE || '0'),
    max_pages: Number($env.SANKHYA_ORDENS_CARGA_MAX_PAGES || '1'),
    include_empty_items: ['1', 'true', 'yes'].includes(String($env.SANKHYA_ORDENS_CARGA_INCLUDE_EMPTY_ITEMS || '').toLowerCase()),
    auth_response_preview: {
      token_type: $json.token_type || data.token_type || '',
      expires_in: $json.expires_in || data.expires_in || null
    }
  }
}];

const raw = ($json.stdout || '').trim();
if (!raw) {
  throw new Error('Script sankhya_ordens_carga_poll.py nao retornou nenhuma saida. Stderr: ' + ($json.stderr || '(vazio)'));
}
let payload;
try {
  payload = JSON.parse(raw);
} catch (parseError) {
  const lines = raw.split('\n').filter(line => line.trim());
  let parsed = false;
  for (let i = lines.length - 1; i >= 0; i--) {
    try {
      payload = JSON.parse(lines[i]);
      parsed = true;
      break;
    } catch (e) { /* try previous line */ }
  }
  if (!parsed) {
    throw new Error('Falha ao interpretar JSON do script poll. Saida bruta (primeiros 500 chars): ' + raw.slice(0, 500) + ' | Stderr: ' + ($json.stderr || '(vazio)'));
  }
}
return [{ json: payload }];

const esc = (value) => {
  const raw = JSON.stringify(value ?? {});
  return raw.replace(/\/g, '\\').replace(/'/g, "''");
};
const escText = (value) => String(value ?? '').replace(/\/g, '\\').replace(/'/g, "''");
const events = Array.isArray($json.events) ? $json.events : [];
const meta = {
  polling: true,
  workflow_name: 'PCP | 15 | Sankhya | Ordens de Carga Poll',
  fetched_at: $json.fetched_at,
  summary: $json.summary || {}
};
let sql;
if (!events.length) {
  sql = `select jsonb_build_object('status','noop','processed',false,'event_count',0,'summary','${esc(meta.summary)}'::jsonb) as result;`;
} else {
  sql = `with src as (
  select value as payload
  from jsonb_array_elements('${esc(events)}'::jsonb)
),
ingested as (
  select ops.ingest_romaneio_event_payload(
    '${escText($json.source_code || 'romaneio_sankhya_webhook')}',
    payload,
    '${esc(meta)}'::jsonb
  ) as result
  from src
)
select jsonb_build_object(
  'status','processed',
  'processed',true,
  'event_count',(select count(*) from src),
  'results',coalesce(jsonb_agg(result), '[]'::jsonb),
  'summary','${esc(meta.summary)}'::jsonb
) as result
from ingested;`;
}
return [{ json: { ...$json, sql_query: sql } }];

const row = $json || {};
let result = row.result ?? row;
if (typeof result === 'string') {
  try {
    result = JSON.parse(result);
  } catch (error) {
    result = { status: 'unknown', raw_result: row.result };
  }
}
const ok = ['processed', 'duplicate_ignored', 'noop'].includes(result.status);
return [{
  json: {
    ok,
    workflow: 'PCP | 15 | Sankhya | Ordens de Carga Poll',
    mode: 'polling',
    ...result
  }
}];
